queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?growth_equity a :growth_equity .
    ?growth_equity p:firm_name ?firm_name .
    BIND(?firm_name AS ?o0)
  }
  UNION
  {
    ?venture_capital a :venture_capital .
    ?venture_capital p:trust_name ?trust_name .
    ?venture_capital p:funding_amount ?funding_amount_f .
    FILTER((STR(?funding_amount_f) = "5000000" || STR(?funding_amount_f) = "5000000.0"))
    BIND(?trust_name AS ?o0)
  }
}

